def solve(s: str) -> int:
    n = len(s)
    max_len = 0

    # Case 1: No swap
    # Find the maximum length of a balanced substring in the original string s
    for i in range(n):
        count0 = 0
        count1 = 0
        for j in range(i, n):
            if s[j] == '0':
                count0 += 1
            else:
                count1 += 1
            if count0 == count1:
                max_len = max(max_len, j - i + 1)

    # Case 2: One swap
    # Iterate over all possible pairs of indices (i, j) to swap
    for i in range(n):
        for j in range(i + 1, n):
            s_list = list(s)
            # Perform the swap
            s_list[i], s_list[j] = s_list[j], s_list[i]
            s_swapped = "".join(s_list)

            # Find the maximum length of a balanced substring in the swapped string
            for start in range(n):
                count0 = 0
                count1 = 0
                for end in range(start, n):
                    if s_swapped[end] == '0':
                        count0 += 1
                    else:
                        count1 += 1
                    if count0 == count1:
                        max_len = max(max_len, end - start + 1)

    return max_len

